// public-facing-worker/src/index.js

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const serviceName = url.pathname.split('/')[1];

    if (!serviceName) {
      return new Response('Missing service name in path', { status: 400 });
    }

    try {
      // Dynamically get the service binding based on the path
      const service = env[serviceName];

      if (!service) {
        return new Response(`Service "${serviceName}" not found or not bound`, { status: 404 });
      }

      // Forward the request to the internal worker
      const modifiedRequest = new Request(request);
      // Remove the service name prefix from the URL path before forwarding
      modifiedRequest.url = url.origin + url.pathname.substring(serviceName.length + 1) + url.search;

      const response = await service.fetch(modifiedRequest);
      return response;
    } catch (error) {
      console.error(`Error forwarding request to ${serviceName}:`, error);
      return new Response(`Internal server error for service ${serviceName}`, { status: 500 });
    }
  },
};


